#!/usr/bin/env python3
# =============================================================================
# SCRIPT METADATA (Generated by g_code)
# =============================================================================
"""
Step ID: step04
Step Name: Steiger's Z-Test for Dependent Correlations
RQ: results/ch6/6.9.5
Generated: 2026-01-19

PURPOSE:
Alternative test using Steiger's Z-test to compare correlation strength between
accuracy/confidence and location x time proxy. Tests if dissociation pattern
is robust to different statistical approaches (convergent evidence with Step 3).

EXPECTED INPUTS:
  - results/ch6/6.9.5/data/step03_merged_data_long.csv
    Columns: UID, location, TSVR_hours, measure, theta
    Rows: 1600 (800 obs x 2 measures)

EXPECTED OUTPUTS:
  - results/ch6/6.9.5/data/step04_steigers_test_results.csv
    Columns: r12, r13, r23, n, z_statistic, p_uncorrected, p_bonferroni, significant, interpretation
    Rows: 1
    Decision D068: BOTH p_uncorrected AND p_bonferroni

  - results/ch6/6.9.5/data/step04_convergent_evidence.txt
    Comparison of mixed model (Step 3) vs Steiger's test conclusions

VALIDATION CRITERIA:
  - p_uncorrected and p_bonferroni columns present (Decision D068)
  - All r values in [-1, 1]
  - n = 800 observations
  - Bonferroni correction: p_bonf = min(p_uncorr * 2, 1.0) for 2 tests

g_code REASONING:
- Approach: Compute 3 correlations (r12=acc-conf, r13=acc-interaction_proxy,
  r23=conf-interaction_proxy), apply Steiger's test for dependent correlations
- Why: Dependent samples (same participants), Steiger's test accounts for
  within-person correlation structure
- Data flow: Merged long data -> Pivot to wide by measure -> Create interaction
  proxy (location_numeric * TSVR_hours) -> Compute correlations -> Steiger's test
- Expected performance: <10 minutes

IMPLEMENTATION NOTES:
- Analysis tool: compare_correlations_dependent from tools.analysis_ctt
- Validation tool: validate_correlation_test_d068 from tools.validation
- Location coding: source=0, destination=1 (numeric proxy)
- Bonferroni: n_tests=2 (mixed model + Steiger's test)
"""
# =============================================================================

import sys
from pathlib import Path
import pandas as pd
import numpy as np
from scipy.stats import pearsonr

# Add project root to path for imports
PROJECT_ROOT = Path(__file__).resolve().parents[4]
sys.path.insert(0, str(PROJECT_ROOT))

# Import tools
from tools.analysis_ctt import compare_correlations_dependent
from tools.validation import validate_correlation_test_d068

# =============================================================================
# Configuration
# =============================================================================

RQ_DIR = Path(__file__).resolve().parents[1]
LOG_FILE = RQ_DIR / "logs" / "step04_steigers_test.log"

# =============================================================================
# Logging Function
# =============================================================================

def log(msg):
    """Write to both log file and console."""
    with open(LOG_FILE, 'a', encoding='utf-8') as f:
        f.write(f"{msg}\n")
    print(msg)

# =============================================================================
# Main Analysis
# =============================================================================

if __name__ == "__main__":
    try:
        log("[START] Step 4: Steiger's Z-Test for Dependent Correlations")

        # =========================================================================
        # STEP 4.1: LOAD MERGED DATA
        # =========================================================================
        log("\n[STEP 4.1] Load merged data from Step 3")
        data_path = RQ_DIR / "data" / "step03_merged_data_long.csv"
        df_long = pd.read_csv(data_path)
        log(f"[LOADED] {len(df_long)} rows")

        # =========================================================================
        # STEP 4.2: CREATE LOCATION x TIME PROXY
        # =========================================================================
        log("\n[STEP 4.2] Create location x time interaction proxy")

        # Encode location as numeric
        df_long['location_numeric'] = df_long['location'].map({'source': 0, 'destination': 1})
        log(f"[CODED] location: source=0, destination=1")

        # Create interaction proxy
        df_long['interaction_proxy'] = df_long['location_numeric'] * df_long['TSVR_hours']
        log(f"[CREATED] interaction_proxy = location_numeric * TSVR_hours")

        # =========================================================================
        # STEP 4.3: PIVOT TO WIDE BY MEASURE
        # =========================================================================
        log("\n[STEP 4.3] Pivot to wide format by measure")

        df_wide = df_long.pivot_table(
            index=['UID', 'location', 'TSVR_hours', 'location_numeric', 'interaction_proxy'],
            columns='measure',
            values='theta'
        ).reset_index()

        df_wide.columns.name = None
        log(f"[PIVOT] {len(df_long)} -> {len(df_wide)} rows (should be 800)")

        # =========================================================================
        # STEP 4.4: COMPUTE CORRELATIONS
        # =========================================================================
        log("\n[STEP 4.4] Compute required correlations")

        # r12: accuracy vs confidence
        r12, p12 = pearsonr(df_wide['accuracy'], df_wide['confidence'])
        log(f"[r12] accuracy vs confidence: r={r12:.4f}, p={p12:.4f}")

        # r13: accuracy vs interaction_proxy
        r13, p13 = pearsonr(df_wide['accuracy'], df_wide['interaction_proxy'])
        log(f"[r13] accuracy vs interaction_proxy: r={r13:.4f}, p={p13:.4f}")

        # r23: confidence vs interaction_proxy
        r23, p23 = pearsonr(df_wide['confidence'], df_wide['interaction_proxy'])
        log(f"[r23] confidence vs interaction_proxy: r={r23:.4f}, p={p23:.4f}")

        n = len(df_wide)
        log(f"[n] Sample size: {n}")

        # =========================================================================
        # STEP 4.5: STEIGER'S Z-TEST
        # =========================================================================
        log("\n[STEP 4.5] Run Steiger's Z-test")

        result = compare_correlations_dependent(r12=r12, r13=r13, r23=r23, n=n)

        log(f"[STEIGER] z-statistic: {result['z_statistic']:.4f}")
        log(f"[STEIGER] p-value: {result['p_value']:.4f}")
        log(f"[STEIGER] r_difference: {result['r_difference']:.4f}")
        log(f"[STEIGER] Significant: {result['significant']}")
        log(f"[STEIGER] Interpretation: {result['interpretation']}")

        # =========================================================================
        # STEP 4.6: APPLY BONFERRONI CORRECTION (DECISION D068)
        # =========================================================================
        log("\n[STEP 4.6] Apply Bonferroni correction (Decision D068)")

        # Family: Within-RQ convergent tests (mixed model + Steiger's)
        # n_tests = 2
        p_uncorrected = result['p_value']
        p_bonferroni = min(p_uncorrected * 2, 1.0)

        log(f"[D068] p_uncorrected: {p_uncorrected:.4f}")
        log(f"[D068] p_bonferroni: {p_bonferroni:.4f} (n_tests=2)")

        # =========================================================================
        # STEP 4.7: CREATE OUTPUT TABLE
        # =========================================================================
        df_steiger = pd.DataFrame([{
            'r12': r12,
            'r13': r13,
            'r23': r23,
            'n': n,
            'z_statistic': result['z_statistic'],
            'p_uncorrected': p_uncorrected,
            'p_bonferroni': p_bonferroni,
            'significant': p_bonferroni < 0.05,
            'interpretation': result['interpretation']
        }])

        # =========================================================================
        # STEP 4.8: VALIDATE D068 COMPLIANCE
        # =========================================================================
        log("\n[STEP 4.8] Validate Decision D068 compliance")

        validation_result = validate_correlation_test_d068(
            correlation_df=df_steiger,
            required_cols=['p_uncorrected', 'p_bonferroni']
        )

        if validation_result['d068_compliant']:
            log(f"[PASS] Decision D068 compliant")
        else:
            log(f"[FAIL] {validation_result['message']}")

        # =========================================================================
        # STEP 4.9: CONVERGENT EVIDENCE CHECK
        # =========================================================================
        log("\n[STEP 4.9] Check convergent evidence with Step 3")

        # Load Step 3 three-way interaction result
        step3_path = RQ_DIR / "data" / "step03_mixed_model_results.csv"
        df_step3 = pd.read_csv(step3_path)

        # Find three-way interaction
        three_way = df_step3[df_step3['term'].str.contains('measure') &
                             df_step3['term'].str.contains('location') &
                             df_step3['term'].str.contains('TSVR')]

        convergent_report = []
        convergent_report.append("="*80)
        convergent_report.append("CONVERGENT EVIDENCE: MIXED MODEL VS STEIGER'S TEST")
        convergent_report.append("="*80)
        convergent_report.append("")

        if len(three_way) > 0:
            three_way_p = three_way.iloc[0]['p_bonferroni']
            three_way_sig = three_way_p < 0.05

            convergent_report.append(f"Mixed Model (Step 3):")
            convergent_report.append(f"  Three-way interaction p_bonferroni: {three_way_p:.4f}")
            convergent_report.append(f"  Significant: {three_way_sig}")
            convergent_report.append("")
            convergent_report.append(f"Steiger's Test (Step 4):")
            convergent_report.append(f"  p_bonferroni: {p_bonferroni:.4f}")
            convergent_report.append(f"  Significant: {p_bonferroni < 0.05}")
            convergent_report.append("")

            if three_way_sig == (p_bonferroni < 0.05):
                convergent_report.append("[CONVERGENT EVIDENCE: AGREE]")
                convergent_report.append("Both tests reach the same conclusion")
                log(f"[AGREE] Mixed model and Steiger's test converge")
            else:
                convergent_report.append("[CONVERGENT EVIDENCE: DISAGREE]")
                convergent_report.append("Tests reach different conclusions - investigate further")
                log(f"[DISAGREE] Mixed model and Steiger's test diverge")
        else:
            convergent_report.append("[ERROR] Could not find three-way interaction in Step 3 results")

        # =========================================================================
        # STEP 4.10: SAVE OUTPUTS
        # =========================================================================
        log("\n[STEP 4.10] Save outputs")

        # Save Steiger's test results
        steiger_path = RQ_DIR / "data" / "step04_steigers_test_results.csv"
        df_steiger.to_csv(steiger_path, index=False, encoding='utf-8')
        log(f"[SAVE] {steiger_path.name}")

        # Save convergent evidence report
        convergent_path = RQ_DIR / "data" / "step04_convergent_evidence.txt"
        with open(convergent_path, 'w', encoding='utf-8') as f:
            f.write('\n'.join(convergent_report))
        log(f"[SAVE] {convergent_path.name}")

        log("[SUCCESS] Step 4 complete")
        sys.exit(0)

    except Exception as e:
        log(f"[ERROR] {str(e)}")
        log("[TRACEBACK] Full error details:")
        import traceback
        with open(LOG_FILE, 'a', encoding='utf-8') as f:
            traceback.print_exc(file=f)
        traceback.print_exc()
        sys.exit(1)
